async (params, browser) => {
  // Open Telegram Web
  await browser.open('https://web.telegram.org/k/')

  // Wait for Telegram to load
  await browser.waitForSelector('.input-search input, .chatlist-chat, .chat-list', 15000)

  // Let app fully initialize
  await browser.wait(2000)

  // Search for the chat
  const search_chat = await browser.evaluate(`const searchInput = document.querySelector('.input-search input') || document.querySelector('input[type="text"]'); if (searchInput) { searchInput.focus(); searchInput.click(); await new Promise(r => setTimeout(r, 300)); searchInput.value = ''; searchInput.dispatchEvent(new Event('input', { bubbles: true })); document.execCommand('insertText', false, params.chat_name); searchInput.dispatchEvent(new Event('input', { bubbles: true })); } return { searched: true }`)

  // Wait for search results
  await browser.wait(2500)

  // Click on the matching chat
  const click_chat = await browser.evaluate(`const chatItems = document.querySelectorAll('.chatlist-chat, .chat-list .ListItem, .search-group .chatlist-chat'); let clicked = false; for (const item of chatItems) { const nameEl = item.querySelector('.peer-title, .user-title, .dialog-title'); if (nameEl && nameEl.textContent.trim().toLowerCase().includes(params.chat_name.toLowerCase())) { item.click(); clicked = true; break; } } if (!clicked && chatItems.length > 0) { chatItems[0].click(); clicked = true; } return { clicked: clicked }`)

  // Wait for messages to load
  await browser.wait(3000)

  // Wait for message bubbles
  await browser.waitForSelector('.message, .bubble, .bubble-content', 10000)

  // Extract messages from chat
  const chat_messages = await browser.evaluate(`const messages = []; const bubbles = document.querySelectorAll('.bubble:not(.is-date), .message'); const startIdx = Math.max(0, bubbles.length - 20); for (let i = startIdx; i < bubbles.length; i++) { const el = bubbles[i]; const authorEl = el.querySelector('.peer-title, .name, .bubble-name .peer-title'); const contentEl = el.querySelector('.text-content, .message-content, .message'); const timeEl = el.querySelector('.time, time, .bubble-content .time'); const content = contentEl ? contentEl.textContent.trim() : ''; if (!content) continue; messages.push({ author: authorEl ? authorEl.textContent.trim() : '', content: content, timestamp: timeEl ? timeEl.textContent.trim() : '', is_outgoing: el.classList.contains('is-out') || el.classList.contains('outgoing') }); } const chatTitle = document.querySelector('.chat-info .peer-title, .top .peer-title'); return { chat_name: chatTitle ? chatTitle.textContent.trim() : params.chat_name, message_count: messages.length, messages: messages }`)

  return chat_messages
}
